import React, { useState } from 'react'
import { Link } from 'react-router-dom'

export default function AddDecoPage(props) {
  const [errM, setErrM] = useState("")
  const [newItemName, setNewItemName] = useState("")
  let checkItem = (event) => {
    let i = event.target.value
    if (i=!"chooseItem"&&i!="Boiler") {
      setErrM("")
      setNewItemName(i)
    }
    if(props.type=="Bathroom"&&i=="Boiler"){
    setErrM("")
    setNewItemName(i)}
    else if(i=="Boiler"){
    setErrM("you can add boiler only to the bathroom")}
    else {
      setErrM("please choose an item")
    }
  }
  let addItem = () => {
    if (newItemName=!"chooseItem"&&errM=="") {
      window.alert("item was added");
      props.addNewDeco(props.name, newItemName)
    }
    else
      window.alert("wrong information product wasnt saved");

  }

return (
  <div>

    <h2>Add new item to the room</h2>
    <h2>Add Item</h2>
             <select name="items" id="items" onChange={checkItem}>
                <option value="chooseItem">Choose item</option>
                <option value="Lamp">Lamp</option>
                <option value="Stereo">Stereo</option>
                <option value="Boiler">Boiler</option>
                <option value="AirCondition">Air condition</option>
            </select>

    <input type="text" onChange={addItem} placeholder='Add' maxLength="7" />
    <h4>{errM}</h4>

    <Link to={"/"}> <button onClick={props.setAddPage(false)}>Add item</button></Link>
  </div>

)
}
